--
-- Table structure for table `kenya_wards`
--

DROP TABLE IF EXISTS `kenya_wards`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `kenya_wards` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `constituency_code` smallint unsigned NOT NULL,
  `county_code` smallint unsigned NOT NULL,
  `name` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `registered_voters` int unsigned NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `kenya_wards_constituency_code_foreign` (`constituency_code`),
  KEY `kenya_wards_county_code_constituency_code_index` (`county_code`,`constituency_code`),
  CONSTRAINT `kenya_wards_constituency_code_foreign` FOREIGN KEY (`constituency_code`) REFERENCES `kenya_constituencies` (`code`) ON DELETE CASCADE,
  CONSTRAINT `kenya_wards_county_code_foreign` FOREIGN KEY (`county_code`) REFERENCES `kenya_counties` (`code`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1451 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

